/**
 * PostToolUse Hooks — Pluggable hook registry。
 *
 * 讓外部 plugin 在每次 tool call 完成後跑 side-effect（日誌、計數、告警等），
 * 不 block tool loop、不影響回覆。
 *
 * 設計原則：
 * - fire-and-forget：hook 可以是 async，但 runPostToolHooks 不 await 結果。
 * - fail-silent：個別 hook 拋錯只 console.error，不影響其他 hook 或主流程。
 * - 單一觸發點：tool-loop.ts 完成 tool call 後呼叫。
 */

import type { RichObservationInput } from "./tool-observer.js";
import { redactArgs } from "./tool-observer.js";

// ─── 型別 ────────────────────────────────────────────────────────────────

/** hook 收到的事件。 */
export interface ToolHookEvent {
  /** 工具名。 */
  name: string;
  /** 原始 args（含敏感值）。hook 若要記錄應用 redactedArgs。 */
  args: Record<string, unknown>;
  /** 已脫敏 args（secret key → [REDACTED]）。 */
  redactedArgs: Record<string, unknown>;
  /** 工具輸出（已截斷至 8KB，同 observation）。 */
  output: string;
  /** 工具是否失敗。 */
  isError: boolean;
  /** Session id。 */
  sessionId: string;
  /** Telegram chat id（可能無）。 */
  chatId?: number;
  /** 本 tool 之前的工具序列（發起序）。 */
  precedingTools: string[];
}

/** PostToolHook 函式簽名。可回傳 void 或 Promise<void>（fire-and-forget，不 await）。 */
export type PostToolHook = (event: ToolHookEvent) => void | Promise<void>;

// ─── Registry ────────────────────────────────────────────────────────────

const hooks: PostToolHook[] = [];

/** 註冊一個 post-tool hook。同一函式重複註冊會被忽略（referential equality）。 */
export function registerHook(hook: PostToolHook): void {
  if (!hooks.includes(hook)) hooks.push(hook);
}

/** 移除已註冊的 hook。未找到時安靜忽略。 */
export function unregisterHook(hook: PostToolHook): void {
  const idx = hooks.indexOf(hook);
  if (idx >= 0) hooks.splice(idx, 1);
}

/** 目前已註冊的 hook 數量（測試 / 診斷用）。 */
export function hookCount(): number {
  return hooks.length;
}

/** 清空所有 hook（測試用）。 */
export function clearHooks(): void {
  hooks.length = 0;
}

// ─── 執行 ────────────────────────────────────────────────────────────────

/**
 * 對所有已註冊 hook 廣播事件。fire-and-forget：
 * - 不 await 任何 hook 的 Promise（不 block tool loop）。
 * - 個別 hook 拋錯只 console.error，不影響其餘。
 */
export function runPostToolHooks(input: RichObservationInput): void {
  if (hooks.length === 0) return;

  const event: ToolHookEvent = {
    name: input.name,
    args: input.args,
    redactedArgs: redactArgs(input.args),
    output: input.output,
    isError: input.isError,
    sessionId: input.sessionId,
    chatId: input.chatId,
    precedingTools: input.precedingTools,
  };

  for (const hook of hooks) {
    try {
      const result = hook(event);
      // async hook：catch 未處理 rejection
      if (result && typeof (result as Promise<void>).catch === "function") {
        (result as Promise<void>).catch((err) => {
          console.error("[tool-hooks] async hook error:", err);
        });
      }
    } catch (err) {
      console.error("[tool-hooks] sync hook error:", err);
    }
  }
}

